-- MSU Main Campus course offerings and prospectus URLs imported from https://msu-prospectus.vercel.app/.
-- Run this after database/schema.sql in the Supabase SQL editor.
-- The app reads these rows from public.course_offerings; they are not hardcoded in the UI.

WITH imported_colleges (id, name, description) AS (
VALUES
  ('college-college-of-agriculture', 'College of Agriculture', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-business-administration-and-accountancy', 'College of Business Administration and Accountancy', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-education', 'College of Education', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('coe', 'College of Engineering', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-fisheries', 'College of Fisheries', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-forestry-and-environmental-studies', 'College of Forestry and Environmental Studies', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('chs', 'College of Health Sciences', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('chtm', 'College of Hospitality and Tourism Management', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('cics', 'College of Information and Computing Sciences', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-law', 'College of Law', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-medicine', 'College of Medicine', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-natural-sciences-and-mathematics', 'College of Natural Sciences and Mathematics', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-public-affairs', 'College of Public Affairs', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-social-sciences-and-humanities', 'College of Social Sciences and Humanities', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('college-college-of-sports-physical-education-and-recreation', 'College of Sports, Physical Education and Recreation', 'Academic college or unit imported from the MSU Main Campus prospectus portal.'),
  ('kfciaas', 'King Faisal Center for Islamic, Arabic and Asian Studies', 'Academic college or unit imported from the MSU Main Campus prospectus portal.')
),
updated_colleges AS (
  UPDATE public.colleges college
  SET description = imported.description
  FROM imported_colleges imported
  WHERE college.id = imported.id
    OR lower(college.name) = lower(imported.name)
  RETURNING college.id
)
INSERT INTO public.colleges (id, name, description)
SELECT imported.id, imported.name, imported.description
FROM imported_colleges imported
CROSS JOIN (SELECT count(*) FROM updated_colleges) updated_count
WHERE NOT EXISTS (
  SELECT 1
  FROM public.colleges college
  WHERE college.id = imported.id
    OR lower(college.name) = lower(imported.name)
);

