INSERT INTO public.course_offerings (
  id,
  college_id,
  college,
  program,
  degree,
  overview,
  prospectus_url,
  tags
)
SELECT
  course.id,
  COALESCE(college.id, course.college_id),
  course.college,
  course.program,
  course.degree,
  course.overview,
  course.prospectus_url,
  course.tags
FROM imported_courses course
LEFT JOIN public.colleges college
  ON lower(college.name) = lower(course.college)
ON CONFLICT (id) DO UPDATE SET
  college_id = EXCLUDED.college_id,
  college = EXCLUDED.college,
  program = EXCLUDED.program,
  degree = EXCLUDED.degree,
  overview = EXCLUDED.overview,
  prospectus_url = EXCLUDED.prospectus_url,
  tags = EXCLUDED.tags,
  updated_at = now();
